import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,e as n}from"./app-be253e4c.js";const c={},o=n(`<h1 id="whereis命令" tabindex="-1"><a class="header-anchor" href="#whereis命令" aria-hidden="true">#</a> whereis命令</h1><p><code>whereis</code>命令用于查找文件，该指令会在特定目录中查找符合条件的文件，该指令只能用于查找二进制文件、源代码文件和<code>man</code>手册页，一般文件的定位需使用<code>locate</code>或<code>find</code>命令。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">whereis</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token function">file</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-b</code>: 仅搜索二进制文件。</li><li><code>-B &lt;dirs&gt;</code>: 更改或限制<code>whereis</code>搜索二进制文件的位置。</li><li><code>-m</code>: 仅搜索源。</li><li><code>-M &lt;dirs&gt;</code>: 更改或限制<code>whereis</code>搜索手册部分的位置。</li><li><code>-s</code>: 仅搜索源。</li><li><code>-S &lt;dirs&gt;</code>: 更改或限制<code>whereis</code>搜索源的位置。</li><li><code>-f</code>: 不显示文件名前的路径名称。</li><li><code>-u</code>: 搜索不寻常的条目，如果文件没有每种请求类型的一个条目，则该文件被认为是不寻常的，即查找不包含指定类型的文件。</li><li><code>-l</code>: 输出有效的查找路径。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>列出<code>whereis</code>命令搜索的目录，默认情况下<code>whereis</code>在环境变量中列出的硬编码路径和目录中搜索命令的文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">whereis</span> <span class="token parameter variable">-l</span>
<span class="token comment"># bin: /usr/bin</span>
<span class="token comment"># bin: /usr/sbin</span>
<span class="token comment"># bin: /usr/lib</span>
<span class="token comment"># ...</span>
</code></pre></div><p>获取有关<code>bash</code>命令的信息，输出的<code>bash</code>是要获取其信息的命令，<code>/bin/bash</code>是二进制文件的路径，<code>/etc/bash.bashrc</code>源文件以及<code>/usr/share/man/man1/bash.1.gz</code>手册页，如果要搜索的命令不存在，<code>whereis</code>将仅打印命令名称。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">whereis</span> <span class="token function">bash</span>
<span class="token comment"># bash: /bin/bash /etc/bash.bashrc /usr/share/man/man1/bash.1.gz</span>
</code></pre></div><p>为<code>whereis</code>命令同时查询<code>netcat</code>与<code>uptime</code>，输出将包含有关<code>netcat</code>和<code>uptime</code>命令的信息。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">whereis</span> netcat <span class="token function">uptime</span>
<span class="token comment"># netcat: /bin/netcat /usr/share/man/man1/netcat.1.gz</span>
<span class="token comment"># uptime: /usr/bin/uptime /usr/share/man/man1/uptime.1.gz</span>
</code></pre></div>`,13),d=[o];function t(i,r){return a(),s("div",null,d)}const p=e(c,[["render",t],["__file","whereis.html.vue"]]);export{p as default};
